import{_ as e,o as r,c as t,ag as l}from"./chunks/framework.DXGyWiRo.js";const o="/img/FlowChart.png",m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"tools/Readme.md","filePath":"tools/Readme.md"}'),i={name:"tools/Readme.md"};function h(s,a,n,c,u,d){return r(),t("div",null,[...a[0]||(a[0]=[l('<h2 id="tools" tabindex="-1">❤️ Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;:heart: Tools&quot;">​</a></h2><p>为了给庞杂的渗透测试工具分类，我们简单将渗透测试流程抽象为以下几个模块：</p><p><img src="'+o+'" alt=""></p><p>每个工具会根据其优势，正确匹配到各个模块中，供大家针对性学习。</p><h3 id="端口扫描" tabindex="-1">⭐ 端口扫描 <a class="header-anchor" href="#端口扫描" aria-label="Permalink to &quot;:star: 端口扫描&quot;">​</a></h3><ul><li><a href="https://github.com/projectdiscovery/naabu" target="_blank" rel="noreferrer">Naabu</a> ：一款用Go语言编写的端口扫描工具，能快速枚举主机上的有效端口。这是一个非常简单的工具，可对主机或主机列表执行快速SYN/CONNECT/UDP扫描并列出所有返回响应的端口。</li></ul><h3 id="url-枚举" tabindex="-1">🐜 URL 枚举 <a class="header-anchor" href="#url-枚举" aria-label="Permalink to &quot;:ant: URL 枚举&quot;">​</a></h3><ul><li><strong>Param Spider：</strong> <a href="https://github.com/devanshbatham/ParamSpider" target="_blank" rel="noreferrer">Param Spider</a> 是一款强大的工具，专门用于从 <strong>Wayback Machine</strong> 等网络存档中挖掘有价值的 URL，以支持进一步的渗透测试工作，如漏洞挖掘、模糊测试等。</li></ul><h3 id="指纹识别" tabindex="-1">👓 指纹识别 <a class="header-anchor" href="#指纹识别" aria-label="Permalink to &quot;:eyeglasses:  指纹识别&quot;">​</a></h3><ul><li><a href="https://github.com/projectdiscovery/httpx" target="_blank" rel="noreferrer">httpx</a> ：一款快速且多功能的HTTP工具包，支持使用retryablehttp库运行多个探针。旨在即使在使用多线程的情况下也能保持结果可靠性。可用于技术栈和Web服务器探测。</li></ul><h3 id="带外测试平台" tabindex="-1">💫 带外测试平台 <a class="header-anchor" href="#带外测试平台" aria-label="Permalink to &quot;:dizzy: 带外测试平台&quot;">​</a></h3><ul><li><p><a href="https://app.interactsh.com/" target="_blank" rel="noreferrer">Interactsh</a>：Interactsh 是一种用于带外数据提取的开源解决方案，它是一种用于检测导致外部交互的错误（例如盲 SQLi、盲 CMDi、SSRF 等）的工具。</p></li><li><p><a href="https://github.com/lijiejie/eyes.sh" target="_blank" rel="noreferrer">EYES</a>：<a href="http://eyes.sh/" target="_blank" rel="noreferrer">eyes.sh</a> 是用来辅助安全测试和漏扫工具的DNS Log / HTTP Log检测工具，基于 <a href="https://github.com/bugscanteam/dnslog/" target="_blank" rel="noreferrer">BugScan DNSLog</a> 优化。</p></li></ul><h3 id="漏洞利用" tabindex="-1">💻 漏洞利用 <a class="header-anchor" href="#漏洞利用" aria-label="Permalink to &quot;:computer: 漏洞利用&quot;">​</a></h3><ul><li><a href="https://github.com/rapid7/metasploit-framework" target="_blank" rel="noreferrer">Metasploit-framework</a> : Metasploit-framework 是一组拥有信息收集、扫描、漏洞利用、漏洞挖掘、后渗透等的开源渗透测试框架，常用于漏洞利用和后渗透测试。</li></ul><h3 id="​漏扫工具" tabindex="-1">🔍 ​漏扫工具 <a class="header-anchor" href="#​漏扫工具" aria-label="Permalink to &quot;:mag: ​漏扫工具&quot;">​</a></h3><ul><li><a href="https://github.com/projectdiscovery/nuclei" target="_blank" rel="noreferrer">Nuclei</a>：Nuclei 用于根据模板向目标发送请求，从而实现零误报，并可在大量主机上提供快速扫描。Nuclei 提供多种协议的扫描，包括 TCP、DNS、HTTP、SSL、文件、Whois、Websocket、Headless、代码等。凭借强大而灵活的模板，Nuclei 可用于模拟各种安全检查。</li><li><a href="https://github.com/zan8in/afrog" target="_blank" rel="noreferrer">afrog</a>：afrog 是一款高性能漏洞扫描工具，速度快、稳定性高，支持自定义 PoC，内置 CVE、CNVD、默认密码、信息泄露、指纹识别、未授权访问、任意文件读取、命令执行等多种漏洞类型，帮助网络安全人员快速验证和修复漏洞，提升安全防御能力。</li></ul><h3 id="自动化漏洞发现" tabindex="-1">⛵自动化漏洞发现 <a class="header-anchor" href="#自动化漏洞发现" aria-label="Permalink to &quot;:boat:自动化漏洞发现&quot;">​</a></h3><ul><li><a href="./自动化漏洞发现/netlas-nuclei-auto.html">Netlas侦察自动化+Nuclei自动扫描</a>：Netlas是一个新工具，提供多种服务，如IP WHOIS查询、DNS查询、攻击面发现、证书搜索、响应搜索等。</li></ul>',18)])])}const b=e(i,[["render",h]]);export{m as __pageData,b as default};
